import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as l,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation اور Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Safety/image-moderation-and-access-mode.md","filePath":"ur/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),r={name:"ur/Safety/image-moderation-and-access-mode.md"};function o(s,e,n,c,m,p){return t(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="image-moderation-اور-access-mode" tabindex="-1">Image Moderation اور Access Mode <a class="header-anchor" href="#image-moderation-اور-access-mode" aria-label="Permalink to &quot;Image Moderation اور Access Mode&quot;">​</a></h1><p>Image moderation uploaded images کو age ratings دیتی ہے۔ Access mode یہ کنٹرول کرتا ہے کہ public access کے ذریعے کون سی ratings دکھائی جا سکتی ہیں۔</p><p>یہ public gallery، public file URLs، اور random image API کو متاثر کرتا ہے۔ admin panel محدود نہیں ہوتا۔ administrators پھر بھی تمام files دیکھ اور manage کر سکتے ہیں۔</p><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>admin panel کھولیں، پھر جائیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>main settings یہ ہیں:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-کیا-کرتا-ہے" tabindex="-1">Access Mode کیا کرتا ہے <a class="header-anchor" href="#access-mode-کیا-کرتا-ہے" aria-label="Permalink to &quot;Access Mode کیا کرتا ہے&quot;">​</a></h2><p>Access mode طے کرتا ہے کہ کون سی age ratings public طور پر دکھائی جا سکتی ہیں۔</p><p>موجودہ modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>صرف General</td></tr></tbody></table><p>default Adult mode ہے۔</p><p>private sites یا mature content والی sites کے لیے Adult mode مناسب ہو سکتا ہے۔ زیادہ conservative public gallery کے لیے Youth، Teen، یا Child mode منتخب کریں۔</p><h2 id="moderation-enable-کرنے-سے-کیا-ہوتا-ہے" tabindex="-1">Moderation Enable کرنے سے کیا ہوتا ہے <a class="header-anchor" href="#moderation-enable-کرنے-سے-کیا-ہوتا-ہے" aria-label="Permalink to &quot;Moderation Enable کرنے سے کیا ہوتا ہے&quot;">​</a></h2><p>moderation enabled ہو تو ImgBed upload کے دوران selected moderation provider کو call کرتا ہے اور detected age rating محفوظ کرتا ہے۔</p><p>main ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>safe public content</td></tr><tr><td>R12</td><td>ہلکا sensitive content</td></tr><tr><td>R16</td><td>درمیانے درجے کا sensitive content</td></tr><tr><td>R18</td><td>adult content</td></tr></tbody></table><p>public access کا فیصلہ کرتے وقت moderation result استعمال ہوتا ہے۔</p><p>اگر moderation enabled نہیں، یا old files کے پاس rating نہیں، تو وہ files unrated سمجھی جاتی ہیں۔ صرف rating نہ ہونے کی وجہ سے unrated files خودکار طور پر public gallery یا random image API سے remove نہیں ہوتیں۔</p><h2 id="moderation-provider-منتخب-کرنا" tabindex="-1">Moderation Provider منتخب کرنا <a class="header-anchor" href="#moderation-provider-منتخب-کرنا" aria-label="Permalink to &quot;Moderation Provider منتخب کرنا&quot;">​</a></h2><p>available providers میں شامل ہیں:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>ہر provider کی requirements مختلف ہیں:</p><ul><li>moderatecontent.com عموماً API Key require کرتا ہے۔</li><li>nsfwjs عموماً API endpoint URL require کرتا ہے۔</li><li>Sightengine API user اور API secret require کرتا ہے۔</li></ul><p>اپنے account، availability، اور detection quality کے مطابق provider منتخب کریں۔ جب moderation enabled اور صحیح configured ہو، ImgBed upload کے دوران image rating لکھنے کی کوشش کرتا ہے۔</p><h2 id="public-gallery-پر-اثر" tabindex="-1">Public Gallery پر اثر <a class="header-anchor" href="#public-gallery-پر-اثر" aria-label="Permalink to &quot;Public Gallery پر اثر&quot;">​</a></h2><p>public gallery access mode کے مطابق files filter کرتی ہے۔</p><p>مثالیں:</p><ul><li>Adult mode: R18 images دکھ سکتی ہیں۔</li><li>Youth mode: R18 images hidden ہوتی ہیں۔</li><li>Teen mode: R16 اور R18 images hidden ہوتی ہیں۔</li><li>Child mode: صرف General images دکھائی جاتی ہیں۔</li></ul><p>یہ صرف normal public access کو متاثر کرتا ہے۔ admin panel پھر بھی تمام files دکھاتا ہے۔</p><h2 id="public-file-urls-پر-اثر" tabindex="-1">Public File URLs پر اثر <a class="header-anchor" href="#public-file-urls-پر-اثر" aria-label="Permalink to &quot;Public File URLs پر اثر&quot;">​</a></h2><p>Public file URLs وہ direct image links ہیں جو visitors کھولتے ہیں۔</p><p>اگر file rating current access mode میں allowed ہے تو ImgBed original image واپس کرتا ہے۔</p><p>اگر rating allowed level سے اوپر ہے، تو normal public access original image واپس نہیں کرتا۔ اس کے بجائے ImgBed configured blocked result یا alternative blocked image واپس کرتا ہے۔</p><p>مثال:</p><ul><li>current mode Child mode ہے۔</li><li>ایک image R18 rated ہے۔</li><li>visitor public URL directly کھولتا ہے۔</li><li>ImgBed اس visitor کو R18 original image واپس نہیں کرتا۔</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>admin panel میں files دیکھنے والے administrators اس restriction سے متاثر نہیں ہوتے۔</p><h2 id="random-image-api-پر-اثر" tabindex="-1">Random Image API پر اثر <a class="header-anchor" href="#random-image-api-پر-اثر" aria-label="Permalink to &quot;Random Image API پر اثر&quot;">​</a></h2><p>random image API بھی candidate pool کو access mode کے مطابق filter کرتی ہے۔</p><p>Child mode میں random images صرف General-rated files سے منتخب ہوتی ہیں۔</p><p>Youth mode میں random images General، R12، اور R16 files سے آ سکتی ہیں، لیکن R18 files سے نہیں۔</p><p>اس سے random image API public gallery restrictions کو bypass نہیں کر سکتی۔</p><h2 id="list-rules-سے-تعلق" tabindex="-1">List Rules سے تعلق <a class="header-anchor" href="#list-rules-سے-تعلق" aria-label="Permalink to &quot;List Rules سے تعلق&quot;">​</a></h2><p>Access mode واحد public access rule نہیں۔ یہ allow/block list rules کے ساتھ مل کر کام کرتا ہے۔</p><p>سادہ الفاظ میں:</p><ul><li>Allowlisted content پہلے public ہوتا ہے۔</li><li>Blocklisted content regular visitors directly نہیں دیکھ سکتے۔</li><li>جو content کسی list میں نہیں، اسے پھر access mode کے against چیک کیا جاتا ہے۔</li></ul><p>اگر image age rating اور list rules دونوں سے restricted ہو، regular visitors پھر بھی original file directly نہیں دیکھ سکتے۔</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Public sites کے لیے:</p><ul><li>moderation enable کریں۔</li><li>site کے audience کے مطابق access mode منتخب کریں۔</li><li>all-age visitors کے لیے Child mode یا Teen mode استعمال کریں۔</li><li>اگر mature content public نہیں دکھانا تو Adult mode سے بچیں۔</li><li>admin panel میں file ratings review کریں اور ضرورت ہو تو manually adjust کریں۔</li></ul><p>Private یا personal sites کے لیے:</p><ul><li>Adult mode عموماً ٹھیک ہے۔</li><li>فائدہ ہو تو moderation enable کریں۔</li><li>ضرورت کے مطابق admin panel میں ratings review اور adjust کریں۔</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="access-mode-بدلنے-کے-بعد-files-admin-panel-سے-غائب-ہوں-گی؟" tabindex="-1">Access Mode بدلنے کے بعد Files Admin Panel سے غائب ہوں گی؟ <a class="header-anchor" href="#access-mode-بدلنے-کے-بعد-files-admin-panel-سے-غائب-ہوں-گی؟" aria-label="Permalink to &quot;Access Mode بدلنے کے بعد Files Admin Panel سے غائب ہوں گی؟&quot;">​</a></h3><p>نہیں۔</p><p>Access mode صرف normal public access کو متاثر کرتا ہے۔ admin panel پر اثر نہیں پڑتا۔</p><h3 id="child-mode-پر-switch-کرنے-کے-بعد-public-gallery-میں-images-کم-کیوں-ہو-گئیں؟" tabindex="-1">Child Mode پر switch کرنے کے بعد Public Gallery میں Images کم کیوں ہو گئیں؟ <a class="header-anchor" href="#child-mode-پر-switch-کرنے-کے-بعد-public-gallery-میں-images-کم-کیوں-ہو-گئیں؟" aria-label="Permalink to &quot;Child Mode پر switch کرنے کے بعد Public Gallery میں Images کم کیوں ہو گئیں؟&quot;">​</a></h3><p>Child mode صرف General-rated files کو public دکھاتا ہے۔ R12، R16، اور R18 files filter ہو جاتی ہیں۔</p><h3 id="کیا-public-urls-adult-images-کھول-سکتی-ہیں؟" tabindex="-1">کیا Public URLs Adult Images کھول سکتی ہیں؟ <a class="header-anchor" href="#کیا-public-urls-adult-images-کھول-سکتی-ہیں؟" aria-label="Permalink to &quot;کیا Public URLs Adult Images کھول سکتی ہیں؟&quot;">​</a></h3><p>اگر current access mode اس rating کو allow نہیں کرتا، تو normal public URLs original image واپس نہیں کرتیں۔</p><h3 id="کیا-random-image-api-restricted-images-واپس-کر-سکتی-ہے؟" tabindex="-1">کیا Random Image API Restricted Images واپس کر سکتی ہے؟ <a class="header-anchor" href="#کیا-random-image-api-restricted-images-واپس-کر-سکتی-ہے؟" aria-label="Permalink to &quot;کیا Random Image API Restricted Images واپس کر سکتی ہے؟&quot;">​</a></h3><p>نہیں۔</p><p>random image API candidates کو current access mode کے مطابق filter کرتی ہے۔</p><h3 id="پرانی-unrated-images-کا-کیا-ہوگا؟" tabindex="-1">پرانی Unrated Images کا کیا ہوگا؟ <a class="header-anchor" href="#پرانی-unrated-images-کا-کیا-ہوگا؟" aria-label="Permalink to &quot;پرانی Unrated Images کا کیا ہوگا؟&quot;">​</a></h3><p>Unrated images صرف اس لیے خودکار طور پر hidden نہیں ہوتیں کہ ان کے پاس moderation results نہیں ہیں۔ آپ بعد میں admin panel میں ان کی ratings adjust کر سکتے ہیں۔</p>',67)])])}const b=i(r,[["render",o]]);export{h as __pageData,b as default};
